#include <signal.h>
#include <stdio.h>

// Shared flag between handler and main - CORRECT declaration
volatile sig_atomic_t shutdown_requested = 0;

// Simple signal handler - only sets flag
void handle_shutdown(int sig) {
 shutdown_requested = 1;
}

int main() {
 struct sigaction sa;
 sa.sa_handler = handle_shutdown;
 sigemptyset(&sa.sa_mask);
 sa.sa_flags = 0; // No SA_RESTART so we can interrupt blocking calls

 if (sigaction(SIGINT, &sa, NULL) == -1) {
 perror("sigaction");
 return 1;
 }

 // Main loop - does actual work after signal
 while (!shutdown_requested) {
 // ... perform main work here ...
 }

 // Cleanup AFTER handler returns - safe to use any function here
 printf("\nCleaning up...\n");
 fflush(stdout);
 // ... close files, free memory, etc. ...

 return 0;
}

#include <signal.h>
#include <stdio.h>
#include <unistd.h>
#include <sys/select.h>

int signal_pipe[2];
volatile sig_atomic_t got_signal = 0;

void signal_handler(int sig) {
 // Write to pipe - write() IS async-signal-safe
 got_signal = 1;
 char a = 1;
 write(signal_pipe[1], &a, 1);
}

int main() {
 // Create pipe before setting up signal handler
 if (pipe(signal_pipe) == -1) {
 perror("pipe");
 return 1;
 }

 struct sigaction sa;
 sa.sa_handler = signal_handler;
 sigemptyset(&sa.sa_mask);
 sa.sa_flags = 0;
 sigaction(SIGTERM, &sa, NULL);

 // Main event loop using select()
 while (1) {
 fd_set readfds;
 FD_ZERO(&readfds);
 FD_SET(signal_pipe[0], &readfds); // Monitor pipe

 int ready = select(signal_pipe[0] + 1, &readfds, NULL, NULL, NULL);

 if (ready > 0 && FD_ISSET(signal_pipe[0], &readfds)) {
 // Drain the pipe
 char buf[10];
 read(signal_pipe[0], buf, sizeof(buf));
 got_signal = 0;

 // Handle signal - now safe to do complex operations
 printf("Signal received, performing cleanup...\n");
 break;
 }
 }

 close(signal_pipe[0]);
 close(signal_pipe[1]);
 return 0;
}

#include <unistd.h>
#include <errno.h>
#include <signal.h>

// Wrapper for read() that handles EINTR
ssize_t safe_read(int fd, void *buf, size_t count) {
 ssize_t n;

 do {
 n = read(fd, buf, count);
 } while (n == -1 && errno == EINTR);

 return n; // Returns -1 on actual error (not EINTR)
}

// Wrapper using SA_RESTART approach
ssize_t safe_read_restart(int fd, void *buf, size_t count) {
 struct sigaction sa, old_sa;

 // Set up handler with SA_RESTART
 sa.sa_handler = SIG_IGN;
 sigemptyset(&sa.sa_mask);
 sa.sa_flags = SA_RESTART;
 sigaction(SIGALRM, &sa, &old_sa);

 ssize_t n = read(fd, buf, count);

 // Restore previous handler
 sigaction(SIGALRM, &old_sa, NULL);

 return n;
}

// Example usage in main
int main() {
 char buffer[1024];

 // Method 1: Manual retry loop
 ssize_t n = safe_read(STDIN_FILENO, buffer, sizeof(buffer));
 if (n < 0) perror("read");

 return 0;
}
